def match(pattern, text):
    node, pos = _parse_alt(pattern, 0)
    n = len(text)
    return _run(node, text, 0, lambda i: i == n)


def _parse_alt(p, i):
    branches = []
    node, i = _parse_concat(p, i)
    branches.append(node)
    while i < len(p) and p[i] == '|':
        node, i = _parse_concat(p, i + 1)
        branches.append(node)
    if len(branches) == 1:
        return branches[0], i
    return ('alt', branches), i


def _parse_concat(p, i):
    parts = []
    while i < len(p) and p[i] not in '|)':
        node, i = _parse_repeat(p, i)
        parts.append(node)
    if len(parts) == 1:
        return parts[0], i
    return ('concat', parts), i


def _parse_repeat(p, i):
    node, i = _parse_atom(p, i)
    if i < len(p):
        c = p[i]
        if c == '*':
            return ('star', node), i + 1
        if c == '+':
            return ('concat', [node, ('star', node)]), i + 1
        if c == '?':
            return ('opt', node), i + 1
    return node, i


def _parse_atom(p, i):
    c = p[i]
    if c == '(':
        node, i = _parse_alt(p, i + 1)
        return node, i + 1
    if c == '[':
        return _parse_class(p, i + 1)
    if c == '.':
        return ('dot',), i + 1
    return ('char', c), i + 1


def _parse_class(p, i):
    negated = False
    if p[i] == '^':
        negated = True
        i += 1
    items = []
    if p[i] == ']':
        items.append((']', ']'))
        i += 1
    while p[i] != ']':
        lo = p[i]
        if i + 2 < len(p) and p[i + 1] == '-' and p[i + 2] != ']':
            items.append((lo, p[i + 2]))
            i += 3
        else:
            items.append((lo, lo))
            i += 1
    return ('class', negated, items), i + 1


def _run(node, text, i, cont):
    kind = node[0]
    if kind == 'char':
        return i < len(text) and text[i] == node[1] and cont(i + 1)
    if kind == 'dot':
        return i < len(text) and cont(i + 1)
    if kind == 'class':
        if i >= len(text):
            return False
        c = text[i]
        inside = False
        for lo, hi in node[2]:
            if lo <= c <= hi:
                inside = True
                break
        return (inside != node[1]) and cont(i + 1)
    if kind == 'concat':
        parts = node[1]

        def run_from(k, j):
            if k == len(parts):
                return cont(j)
            return _run(parts[k], text, j, lambda j2: run_from(k + 1, j2))

        return run_from(0, i)
    if kind == 'alt':
        for branch in node[1]:
            if _run(branch, text, i, cont):
                return True
        return False
    if kind == 'opt':
        return _run(node[1], text, i, cont) or cont(i)
    if kind == 'star':
        inner = node[1]

        def rep(j):
            # only keep looping if the iteration consumed input,
            # otherwise empty-matching inners would loop forever
            if _run(inner, text, j, lambda k: k != j and rep(k)):
                return True
            return cont(j)

        return rep(i)
    return False
